"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[7844],{3126:(D,B,p)=>{p.r(B),p.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-b4961a12","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%B1%D0%BE%D0%BB%D1%8C%D1%88%D0%B0%D0%BA%D0%BE%D0%B2-%D1%81%D1%82%D1%80%D1%83%D0%BA%D1%82%D1%83%D1%80%D1%8B-%D0%B8-%D0%BF%D1%80%D0%BE%D0%B5%D0%BA%D1%82%D0%B8%D1%80%D0%BE%D0%B2%D0%B0%D0%BD%D0%B8%D0%B5-%D0%B8%D0%BD%D1%84%D0%BE%D1%80%D0%BC%D0%B0%D1%86%D0%B8%D0%BE%D0%BD%D0%BD%D1%8B%D1%85-%D1%81%D0%B8%D1%81%D1%82%D0%B5%D0%BC.html","title":"Структуры и проектирование информационных систем","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1731007587000},"filePathRelative":"глушковские-чтения/большаков-структуры-и-проектирование-информационных-систем.md"}')},4180:(D,B,p)=>{p.r(B),p.d(B,{default:()=>r});var l=p(6252);const i=(0,l._)("h1",{id:"структуры-и-проектирование-информационных-систем",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#структуры-и-проектирование-информационных-систем","aria-hidden":"true"},"#"),(0,l.Uk)(" Структуры и проектирование информационных систем")],-1),e=(0,l._)("p",null,"Большаков В. Н., г. Киев.",-1),t=(0,l.uE)("<p>Обобщая опыт создания автоматизированных и автоматических систем, в начале 70-х Виктор Михайлович Глушков сформулировал основные принципы построения автоматизированных систем управления [1,2]. Соблюдение этих принципов остается актуальным и при проектировании современных информационных систем различных классов (корпоративных, интеллектуальных, распределенных и других). Одним из важнейших принципов был назван принцип системного подхода к проектированию. При этом В. М. Глушков выделял две стороны системного подхода: первая сторона — это изучение систем как целого, изучение взаимодействия элементов внутри системы и взаимодействий систем внутри их комплексов; вторая сторона системного подхода — «извлечение некоторых общих свойств из изучения систем того или иного конкретного вида и использование их для изучения систем другой природы» [3]. Таким образом, вместе с представлением системы как множества элементов используются понятия взаимодействие и свойство.</p><p>Иначе говоря, вместе с множеством объектов, ассоциированных с системой (элементы системы, сама система, внешние по отношению к системе объекты), необходимо рассматривать отношения (взаимодействия) объектов и их свойства.</p><p>Если множество объектов задается экстенсионально, то есть перечнем элементов множества, то свойство задается перечислением объектов, для которых выполнено это свойство, а отношение — перечислением пар объектов, для которых определено отношение. При формальных записях для определения свойств и отношений удобно пользоваться операциями декартового произведения множеств (декартиана) и взятия частей (булеана). Далее можно говорить о свойствах объектов, свойствах отношений, отношениях свойств, свойствах свойств и т. д. Множества, полученные посредством операций произведения (декартиана) и взятия частей (булеана), называют шкалой множеств с некоторой базой (в нашем случае с базой из одного множества).</p><p>Если во множестве некоторой шкалы множеств задано подмножество, то каждый элемент этого подмножества определяет на базе этой шкалы структуру [4]. В работе «Архитектура математики» после пояснения того, что следует понимать под математической структурой Н. Бурбаки указали основные, базовые типы структур[5]:</p><ol><li><p>структуры, определяемые отношениями порядка;</p></li><li><p>алгебраические структуры;</p></li><li><p>топологические структуры.</p></li></ol><p>Для описания структур порядка на множестве используется подмножество декартова произведения множества на себя. Для описания алгебраических структур используется произведение декартиана на исходное множество, а для описания топологических структур используются только булеаны. Таким образом, на базе, состоящей из одного множества объектов, возможно формальное определение того, что является свойствами, отношениями, а также отношениями объектов, отношениями свойств и отношениями отношений, свойствами объектов, свойствами свойств и свойствами отношений.</p><p>Выделение базовых математических структур было поддержано Жаном Пиаже — известным психологом, который отмечал: «что если проследить до самых истоков психологическое развитие арифметических и геометрических операций в сознании ребенка и особенно операций логических..., то вновь находят... вначале фундаментальные тенденции к организации целого или системы, вне которой элементы не имеют ни значения, ни вообще существования, а затем распределение этих систем совокупностей по трем типам, которые в точности соответствуют структурам алгебраическим, структурам порядка и топологии»[6].</p><p>Можно сделать вывод, что важнейшим процессом в ходе проектирования различного рода систем, моделирования предметных областей и создания баз данных, баз знаний и различных онтологий для интеллектуальных систем является структурирование информации путем формального описания объектов, свойств и отношений, в результате которого образуются иерархии, отображаемые в структурах порядка, классификации на основе свойств объектов и описания функциональных зависимостей.</p><p>Список использованных источников</p><ol><li><p>Глушков В.М. Основные принципы построения автоматизированных систем организационного управления //Управляющие системы и машины.-1972.-No1.-С.9-18.</p></li><li><p>Глушков В.М. Введение в АСУ (монография).-Киев.-1972.- Техніка.</p></li><li><p>Глушков В.М. Теория рака с позиций общей теории систем.- Киев.-1979.-20с. (цитируется по В. М. Глушков Кибернетика, вычислительная техника, информатика. Избранные труды в 3т.-Киев:Наук. думка, 1990.).</p></li><li><p>Энциклопедия кибернетики.-Киев: Гл. ред. Глушков В.М.-1974.-УРЭ.-2, С.19</p></li><li><p>Бурбаки Н. Архитектура математики (перев. с франц.).-Матем.просв.-1960.- выпуск 5.-С.99-112</p></li><li><p>Пиаже Ж. Структуры математические и операторные структуры мышления// Пиаже Ж. и др. Преподавание математики. Учпедгиз.-Москва.-1960.- С.10-30.</p></li></ol>",10),a={},r=(0,p(3744).Z)(a,[["render",function(D,B){const p=(0,l.up)("RouterLink");return(0,l.wg)(),(0,l.iD)("div",null,[i,e,(0,l._)("p",null,[(0,l.Uk)("Из материалов конференции "),(0,l.Wm)(p,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,l.w5)((()=>[(0,l.Uk)("«Глушковские чтения»")])),_:1}),(0,l.Uk)(" 2019 года.")]),t])}]])}}]);